import { useEffect, useState, useRef, useCallback } from 'react';
import { chatApi } from '../api/client';
import { useToast } from '../context/ToastContext';
import { IMG_CHAT, IMG_GRAMMAR } from '../assets/images';
import './Chat.css';

const SYSTEM_PROMPT = `You are Pengwin, a friendly English language tutor AI shaped like a penguin.
When the user writes in English:
1. Identify and correct grammar/spelling errors clearly.
2. Suggest a better, more natural version of their sentence.
3. Briefly explain why the correction is needed.
4. Keep your tone encouraging, warm, and use occasional 🐧 emoji.
Format: ❌ error → ✅ correction`;

const SUGGESTIONS = [
  'Yesterday I go to school with my friend.',
  'She is more taller than her sister.',
  'I have been to Paris last year.',
  'He don\'t know the answer.',
];

function buildTutorReply(text) {
  const trimmed = text.trim();
  if (!trimmed) {
    return 'Please send a sentence and I will help you improve it.';
  }

  const replacements = [
    { from: /\bI go\b/gi, to: 'I went' },
    { from: /\bHe don\'t\b/gi, to: "He doesn't" },
    { from: /\bShe don\'t\b/gi, to: "She doesn't" },
    { from: /\bmore taller\b/gi, to: 'taller' },
    { from: /\bmore better\b/gi, to: 'better' },
    { from: /\blast year\b/gi, to: 'last year' },
  ];

  let corrected = trimmed;
  replacements.forEach(({ from, to }) => {
    corrected = corrected.replace(from, to);
  });

  if (!/[.!?]$/.test(corrected)) corrected += '.';

  if (corrected === trimmed) {
    return [
      '✅ Your sentence looks good!',
      `💡 Natural version: ${corrected}`,
      'Great job. Keep practicing and try adding one more detail to make it richer.'
    ].join('\n');
  }

  return [
    `❌ ${trimmed}`,
    `✅ ${corrected}`,
    'Why: I fixed common grammar patterns (tense/verb agreement/comparative form) to make the sentence more natural.'
  ].join('\n');
}

function Message({ msg }) {
  const isUser = msg.role==='user';
  const time   = new Date(msg.created_at).toLocaleTimeString('vi-VN',{hour:'2-digit',minute:'2-digit'});
  return (
    <div className={`msg-row ${isUser?'user':'ai'}`}>
      {!isUser && <img src={IMG_CHAT} className="msg-avatar" alt="AI" />}
      <div className={`msg-bubble ${isUser?'user-bubble':'ai-bubble'}`}>
        <div className="msg-content" style={{whiteSpace:'pre-wrap'}}>{msg.content}</div>
        <div className="msg-time">{time}</div>
      </div>
      {isUser && <div className="msg-avatar-user">{msg.role==='user'?'👤':''}</div>}
    </div>
  );
}

function Typing() {
  return (
    <div className="msg-row ai">
      <img src={IMG_CHAT} className="msg-avatar" alt="AI" />
      <div className="ai-bubble msg-bubble typing-bubble">
        <span/><span/><span/>
      </div>
    </div>
  );
}

export default function Chat() {
  const toast     = useToast();
  const bottomRef = useRef(null);
  const [messages, setMessages] = useState([]);
  const [input,    setInput]    = useState('');
  const [loading,  setLoading]  = useState(true);
  const [typing,   setTyping]   = useState(false);

  useEffect(()=>{
    chatApi.history().then(setMessages).catch(e=>toast(e.message,'error')).finally(()=>setLoading(false));
  },[toast]);
  useEffect(()=>{ setTimeout(()=>bottomRef.current?.scrollIntoView({behavior:'smooth'}),50); },[messages,typing]);

  const callAI = useCallback(async (history) => {
    setTyping(true);
    try {
      const latestUserMessage = [...history].reverse().find(m => m.role === 'user');
      const text = buildTutorReply(latestUserMessage?.content || '');
      const saved = await chatApi.saveAI(text);
      setMessages(prev=>[...prev,saved]);
    } catch(e) { toast(e.message || 'Không thể lưu phản hồi AI','error'); }
    finally { setTyping(false); }
  },[toast]);

  const handleSend = async () => {
    const text = input.trim();
    if(!text||typing) return;
    setInput('');
    try {
      const saved = await chatApi.send(text);
      const newH  = [...messages, saved];
      setMessages(newH);
      await callAI(newH);
    } catch(e) { toast(e.message,'error'); }
  };

  return (
    <div className="chat-page">
      <div className="chat-topbar">
        <div>
          <h1 className="page-title" style={{marginBottom:2}}>💬 AI Writing Coach</h1>
          <p className="page-sub">Viết tự do — Pengwin AI sẽ sửa lỗi ngữ pháp cho bạn!</p>
        </div>
        <button className="btn btn-ghost btn-sm"
          onClick={async()=>{if(!window.confirm('Xóa lịch sử chat?'))return;await chatApi.clear();setMessages([]);toast('Đã xóa!');}}
          disabled={messages.length===0}>
          🗑 Xóa chat
        </button>
      </div>

      <div className="chat-area">
        {loading ? <div className="loading-page"><div className="spinner spinner-lg"/></div>
        : messages.length===0 ? (
          <div className="chat-empty">
            <img src={IMG_GRAMMAR} style={{width:90,animation:'float 3s ease-in-out infinite',marginBottom:16}} alt="" />
            <h3 style={{fontFamily:'var(--font-head)',fontSize:20,color:'var(--navy)',marginBottom:8}}>Xin chào! Tôi là Pengwin AI 🐧</h3>
            <p style={{fontSize:14,color:'var(--text2)',fontWeight:600,marginBottom:20,maxWidth:360}}>
              Viết bất kỳ câu nào bằng tiếng Anh và tôi sẽ giúp bạn cải thiện ngữ pháp!
            </p>
            <div style={{width:'100%',maxWidth:420}}>
              <p style={{fontSize:11,fontWeight:800,textTransform:'uppercase',letterSpacing:'0.08em',color:'var(--text3)',marginBottom:10}}>💡 Thử các câu này:</p>
              {SUGGESTIONS.map((s,i)=>(
                <button key={i} className="sug-btn" onClick={()=>setInput(s)}>{s}</button>
              ))}
            </div>
          </div>
        ) : (
          <div className="messages">
            {messages.map(m=><Message key={m.id} msg={m}/>)}
            {typing && <Typing/>}
            <div ref={bottomRef}/>
          </div>
        )}
      </div>

      <div className="chat-input-area">
        <textarea className="chat-textarea"
          placeholder="Viết câu tiếng Anh... (Enter gửi, Shift+Enter xuống dòng)"
          value={input} onChange={e=>setInput(e.target.value)}
          onKeyDown={e=>{if(e.key==='Enter'&&!e.shiftKey){e.preventDefault();handleSend();}}}
          rows={2} disabled={typing} />
        <button className="btn btn-primary chat-send" onClick={handleSend} disabled={!input.trim()||typing}>
          {typing?<span className="spinner"/>:'↑'}
        </button>
      </div>
    </div>
  );
}
